import json,urllib.request; u='http://127.0.0.1:8001';

def r(path, method='GET', token=None, payload=None):
    data=None if payload is None else json.dumps(payload).encode();
    headers={'Content-Type':'application/json'};
    headers.update({'Authorization':f'Bearer {token}'} if token else {});
    req=urllib.request.Request(u+path, data=data, headers=headers, method=method);
    with urllib.request.urlopen(req, timeout=20) as resp:
        return resp.status, json.loads(resp.read().decode())

